fn call_twice(f: impl Fn()) {
    f();
    f();
}
let msg = "hello";
call_twice(|| println!("{msg}"));

fn call_twice_mut(mut f: impl FnMut()) {
    f();
    f();
}
let mut count = 0;
call_twice_mut(|| { count += 1; });
assert_eq!(count, 2);

fn call_once(f: impl FnOnce() -> String) -> String {
    f()
}
