let result = call_once(move || {
    format!("Hello, {name}") // consumes name
});

// FnOnce is the supertrait:
//   FnOnce (all closures)
//     |-- FnMut (can be called multiple times)
//           |-- Fn (can be called without mutation)

// If you accept FnOnce, any closure works
// If you accept Fn, only non-mutating closures work

// Use Fn when you call the closure multiple times without mutation
fn filter<F: Fn(&i32) -> bool>(data: &[i32], f: F) -> Vec<&i32> { ... }

// Use FnMut when the closure needs to mutate state
fn for_each<F: FnMut(i32)>(data: &[i32], mut f: F) { ... }

// Use FnOnce when you call the closure exactly once
fn setup<F: FnOnce() -> Config>(f: F) -> Config { f() }

fn apply(value: i32, f: impl Fn(i32) -> i32) -> i32 {
    f(value)
}
let result = apply(5, |x| x * 2);

fn apply<F: Fn(i32) -> i32>(value: i32, f: F) -> i32 {
    f(value)
}

fn apply<F>(value: i32, f: F) -> i32
where
    F: Fn(i32) -> i32,
{
    f(value)
}

fn apply(value: i32, f: &dyn Fn(i32) -> i32) -> i32 {
    f(value)
}

fn apply(value: i32, f: fn(i32) -> i32) -> i32 {
    f(value)
}
fn double(x: i32) -> i32 { x * 2 }
let result = apply(5, double);

let multiplier = 3;
