// Fn trait: can capture environment
let closure: Box<dyn Fn(i32) -> i32> = Box::new(|x| x * multiplier);

fn make_adder(x: i32) -> impl Fn(i32) -> i32 {
    move |y| x + y
}
let add5 = make_adder(5);
assert_eq!(add5(3), 8);

fn make_greeting(formal: bool) -> Box<dyn Fn(&str) -> String> {
    if formal {
        Box::new(|name| format!("Good day, {name}."))
    } else {
        Box::new(|name| format!("Hey {name}!"))
    }
}

fn counter() -> impl FnMut() -> i32 {
    let mut count = 0;
    move || {
        count += 1;
        count
    }
}
let mut c = counter();
assert_eq!(c(), 1);
assert_eq!(c(), 2);

struct Callback<F: Fn(i32) -> i32> {
    func: F,
}
impl<F: Fn(i32) -> i32> Callback<F> {
    fn call(&self, x: i32) -> i32 {
        (self.func)(x)
    }
}

struct Handler {
    callback: Box<dyn Fn(String) -> String>,
}
impl Handler {
    fn new(f: impl Fn(String) -> String + 'static) -> Self {
        Handler { callback: Box::new(f) }
    }
    fn handle(&self, input: String) -> String {
        (self.callback)(input)
    }
}

